import React, { useState, useEffect } from 'react';
import { getBooks, borrowBook } from '../../services/api';
import { toast } from 'react-hot-toast';
import { useAuth } from '../../contexts/AuthContext';
import { useNavigate } from 'react-router-dom';

const BookList = () => {
  const [books, setBooks] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filters, setFilters] = useState({
    genre: '',
    page: 1,
    limit: 12
  });
  const [pagination, setPagination] = useState({
    currentPage: 1,
    totalPages: 1,
    totalItems: 0
  });

  const { user } = useAuth();
  const navigate = useNavigate();

  useEffect(() => {
    loadBooks();
  }, [filters.page, filters.genre]);

  const loadBooks = async () => {
    try {
      setLoading(true);
      const response = await getBooks(filters);
      setBooks(response.data.data);
      setPagination(response.data.pagination);
    } catch (error) {
      console.error('Erreur chargement livres:', error);
      toast.error('Impossible de charger les livres');
    } finally {
      setLoading(false);
    }
  };

  const handleBorrow = async (bookId) => {
    if (!user) {
      toast.error('Veuillez vous connecter pour emprunter');
      navigate('/login');
      return;
    }

    try {
      await borrowBook({ 
        bookId, 
        dueDate: new Date(Date.now() + 14 * 24 * 60 * 60 * 1000) // 14 jours
      });
      toast.success('📚 Livre emprunté avec succès !');
      loadBooks(); // Recharger la liste pour mettre à jour les disponibilités
    } catch (error) {
      // Les erreurs sont déjà gérées par l'intercepteur
    }
  };

  const handleGenreChange = (genre) => {
    setFilters({ ...filters, genre, page: 1 });
  };

  const handlePageChange = (newPage) => {
    setFilters({ ...filters, page: newPage });
  };

  if (loading) {
    return (
      <div className="flex justify-center items-center min-h-screen">
        <div className="text-xl">Chargement des livres...</div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-100">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {/* Header */}
        <div className="mb-8">
          <h1 className="text-3xl font-bold text-gray-900 mb-4">
            Catalogue des livres
          </h1>

          {/* Filtres par genre */}
          <div className="flex flex-wrap gap-2">
            {['Tous', 'Fiction', 'Science Fiction', 'Fantasy', 'Mystère', 'Biographie'].map((genre) => (
              <button
                key={genre}
                onClick={() => handleGenreChange(genre === 'Tous' ? '' : genre)}
                className={`px-4 py-2 rounded-full text-sm font-medium transition ${
                  (genre === 'Tous' && filters.genre === '') || filters.genre === genre
                    ? 'bg-blue-600 text-white'
                    : 'bg-white text-gray-700 hover:bg-gray-200'
                }`}
              >
                {genre}
              </button>
            ))}
          </div>
        </div>

        {/* Grille des livres */}
        {books.length === 0 ? (
          <div className="text-center py-12">
            <p className="text-gray-500 text-lg">Aucun livre trouvé</p>
          </div>
        ) : (
          <>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
              {books.map((book) => (
                <div
                  key={book._id}
                  className="bg-white rounded-lg shadow-md overflow-hidden hover:shadow-lg transition"
                >
                  {/* Couverture */}
                  <div className="h-48 bg-gray-200 flex items-center justify-center">
                    {book.coverImage ? (
                      <img
                        src={book.coverImage}
                        alt={book.title}
                        className="w-full h-full object-cover"
                      />
                    ) : (
                      <span className="text-6xl">📖</span>
                    )}
                  </div>

                  {/* Informations */}
                  <div className="p-4">
                    <h3 className="font-bold text-lg mb-1">{book.title}</h3>
                    <p className="text-gray-600 text-sm mb-2">par {book.author}</p>

                    {/* Genres */}
                    <div className="flex flex-wrap gap-1 mb-3">
                      {book.genres?.slice(0, 2).map((g) => (
                        <span
                          key={g}
                          className="px-2 py-1 bg-gray-100 text-xs rounded-full"
                        >
                          {g}
                        </span>
                      ))}
                    </div>

                    {/* Disponibilité */}
                    <div className="flex justify-between items-center mb-3">
                      <span className={`text-sm font-medium ${
                        book.availableCopies > 0 ? 'text-green-600' : 'text-red-600'
                      }`}>
                        {book.availableCopies > 0 
                          ? `${book.availableCopies}/${book.totalCopies} disponible${book.availableCopies > 1 ? 's' : ''}`
                          : 'Indisponible'}
                      </span>
                      <span className="text-sm text-gray-500">
                        ⭐ {book.averageRating?.toFixed(1) || 'N/A'}
                      </span>
                    </div>

                    {/* Bouton emprunter */}
                    <button
                      onClick={() => handleBorrow(book._id)}
                      disabled={book.availableCopies === 0}
                      className={`w-full py-2 px-4 rounded-lg text-sm font-medium transition ${
                        book.availableCopies > 0
                          ? 'bg-blue-600 text-white hover:bg-blue-700'
                          : 'bg-gray-300 text-gray-500 cursor-not-allowed'
                      }`}
                    >
                      {book.availableCopies > 0 ? 'Emprunter' : 'Indisponible'}
                    </button>

                    {/* Voir détails */}
                    <button
                      onClick={() => navigate(`/books/${book._id}`)}
                      className="w-full mt-2 py-2 px-4 border border-gray-300 rounded-lg text-sm font-medium text-gray-700 hover:bg-gray-50 transition"
                    >
                      Voir détails
                    </button>
                  </div>
                </div>
              ))}
            </div>

            {/* Pagination */}
            {pagination.totalPages > 1 && (
              <div className="flex justify-center mt-8 space-x-2">
                <button
                  onClick={() => handlePageChange(pagination.currentPage - 1)}
                  disabled={pagination.currentPage === 1}
                  className="px-4 py-2 border rounded-lg disabled:opacity-50"
                >
                  ← Précédent
                </button>
                <span className="px-4 py-2">
                  Page {pagination.currentPage} sur {pagination.totalPages}
                </span>
                <button
                  onClick={() => handlePageChange(pagination.currentPage + 1)}
                  disabled={pagination.currentPage === pagination.totalPages}
                  className="px-4 py-2 border rounded-lg disabled:opacity-50"
                >
                  Suivant →
                </button>
              </div>
            )}
          </>
        )}
      </div>
    </div>
  );
};

export default BookList;
